import{_ as i,c as s,o as a,aj as t}from"./chunks/framework.DJhf6x5b.js";const k=JSON.parse('{"title":"TIGER Reproduction Notes","description":"How TIGER is run in torch-rechub, including the semantic-ID pipeline, run modes, and the toy training workflow","frontmatter":{"title":"TIGER Reproduction Notes","description":"How TIGER is run in torch-rechub, including the semantic-ID pipeline, run modes, and the toy training workflow"},"headers":[],"relativePath":"blog/tiger_reproduction.md","filePath":"en/blog/tiger_reproduction.md"}'),n={name:"blog/tiger_reproduction.md"};function o(d,e,l,r,h,c){return a(),s("div",null,[...e[0]||(e[0]=[t(`<h2 id="tiger-in-torch-rechub" tabindex="-1">TIGER in torch-rechub <a class="header-anchor" href="#tiger-in-torch-rechub" aria-label="Permalink to “TIGER in torch-rechub”">​</a></h2><p>This document describes how TIGER (Transformer Index for GEnerative Recommenders) is implemented and run in <code>torch-rechub</code>. TIGER frames &quot;predict the next item&quot; as a sequence-to-sequence task of &quot;generate the next item&#39;s semantic ID&quot;: each item is first quantized by RQ-VAE into a tuple of codebook tokens (a <em>semantic ID</em>, e.g. <code>&lt;a_1&gt;&lt;b_3&gt;&lt;c_5&gt;</code>), then T5 autoregressively generates the next item&#39;s semantic ID, constrained to legal items via prefix-restricted beam search.</p><p>The example scripts follow the same &quot;one script per dataset&quot; layout as HSTU / HLLM:</p><ul><li><code>examples/generative/run_tiger_movielens.py</code></li><li><code>examples/generative/run_tiger_amazon_books.py</code></li></ul><hr><h2 id="_1-module-layout" tabindex="-1">1. Module Layout <a class="header-anchor" href="#_1-module-layout" aria-label="Permalink to “1. Module Layout”">​</a></h2><ul><li><strong>Model</strong>: <code>torch_rechub/models/generative/tiger.py</code><ul><li><code>TIGERModel</code>: subclasses <code>transformers.T5ForConditionalGeneration</code>, adding <code>set_hyper(temperature)</code> and a temperature-scaled <code>ranking_loss</code>.</li></ul></li><li><strong>Dataset &amp; constrained decoding</strong>: <code>torch_rechub/utils/data.py</code><ul><li><code>TigerSeqDataset</code>: maps item-id sequences in <code>inter.json</code> to semantic-ID strings and applies a leave-one-out split for <code>train</code> / <code>valid</code> / <code>test</code>.</li><li><code>Trie</code>: builds a prefix tree over all legal semantic IDs and yields a <code>prefix_allowed_tokens_fn</code> for constrained beam search.</li></ul></li><li><strong>Semantic-ID generation</strong>: <code>examples/generative/run_rqvae_amazon_books.py</code><ul><li>Trains an RQ-VAE over item embeddings and exports <code>semantic_ids.json</code>.</li></ul></li><li><strong>Example scripts</strong>: <code>run_tiger_movielens.py</code> / <code>run_tiger_amazon_books.py</code>, each implementing <code>train</code> / <code>test</code> and toy-data generation.</li></ul><hr><h2 id="_2-data-format" tabindex="-1">2. Data Format <a class="header-anchor" href="#_2-data-format" aria-label="Permalink to “2. Data Format”">​</a></h2><p>TIGER needs two JSON files:</p><ul><li><strong><code>inter.json</code></strong>: <code>{user_id: [item_id, item_id, ...]}</code>, each user&#39;s chronologically ordered item-id history. Item ids are 1-based; <code>0</code> is reserved for padding.</li><li><strong><code>semantic_ids.json</code></strong>: <code>{item_id: [&quot;&lt;a_..&gt;&quot;, &quot;&lt;b_..&gt;&quot;, ...]}</code>, a semantic ID for every item id that appears in <code>inter.json</code>.</li></ul><p><code>TigerSeqDataset</code> leave-one-out split:</p><ul><li><code>train</code>: expand the history <code>items[:-2]</code> into multiple <code>(history, next_item)</code> samples.</li><li><code>valid</code>: history is <code>items[:-2]</code>, label is <code>items[-2]</code>.</li><li><code>test</code>: history is <code>items[:-1]</code>, label is <code>items[-1]</code>.</li></ul><p>So each user needs at least 3 interactions to produce a training sample.</p><hr><h2 id="_3-run-modes" tabindex="-1">3. Run Modes <a class="header-anchor" href="#_3-run-modes" aria-label="Permalink to “3. Run Modes”">​</a></h2><p>Both scripts use <code>--mode</code> to select the stage(s):</p><table tabindex="0"><thead><tr><th>mode</th><th>Description</th></tr></thead><tbody><tr><td><code>generate-toy-data</code></td><td>Write a small synthetic dataset to <code>--data_inter_path</code> / <code>--data_indice_path</code> (the exact paths the loader reads)</td></tr><tr><td><code>prepare-data</code></td><td>MovieLens only: build <code>inter.json</code> and <code>movie_id_map.json</code> from the real <code>ratings.dat</code></td></tr><tr><td><code>train</code></td><td>Add semantic-ID tokens, <code>resize_token_embeddings</code>, train T5 from scratch (random init, no pretrained weights), save tokenizer / config / model to <code>--output_dir</code></td></tr><tr><td><code>test</code></td><td>Load from <code>--ckpt_path</code> (defaults to <code>--output_dir</code>), run constrained beam search, report hit@k / ndcg@k</td></tr><tr><td><code>all</code></td><td>Run <code>generate-toy-data</code> → <code>train</code> → <code>test</code> (default)</td></tr></tbody></table><p>Key implementation details:</p><ul><li><strong>Trained from scratch, no pretrained weights</strong>: per the TIGER paper the T5 encoder-decoder is randomly initialized and trained from scratch (the semantic-ID vocabulary is not natural language, so pretrained NL weights are not useful). <code>train()</code> builds the architecture from <code>--base_model</code>&#39;s config via <code>TIGERModel(config)</code>; <code>--base_model</code> only supplies the architecture/config and tokenizer, not pretrained weights.</li><li><strong>Semantic-ID tokens must be added before training</strong>: <code>train()</code> calls <code>tokenizer.add_tokens(dataset.get_new_tokens())</code> and then <code>resize_token_embeddings</code>; otherwise tokens like <code>&lt;a_1&gt;</code> are split into sub-words and training is meaningless.</li><li><strong>Generated and read paths are identical</strong>: <code>generate-toy-data</code> writes to the same paths the dataset reads, avoiding a &quot;generated filename ≠ read filename&quot; mismatch.</li><li><strong><code>test</code> loads weights with the checkpoint&#39;s own config</strong>: this avoids passing a grown <code>vocab_size</code> into <code>from_pretrained</code> (which would raise an embedding-size mismatch); the tokenizer is then reconciled and the model resized only if needed before evaluation.</li></ul><hr><h2 id="_4-quick-toy-run" tabindex="-1">4. Quick Toy Run <a class="header-anchor" href="#_4-quick-toy-run" aria-label="Permalink to “4. Quick Toy Run”">​</a></h2><p>No external data is required; this runs end to end on CPU:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> examples/generative</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Synthetic MovieLens-shaped data</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run_tiger_movielens.py</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --mode</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> all</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --toy_num_users</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 16</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --toy_num_items</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 20</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --epochs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --per_device_batch_size</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 4</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --num_beams</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 4</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --test_batch_size</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --num_workers</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Built-in Amazon-Books toy data</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run_tiger_amazon_books.py</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --mode</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> all</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --epochs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --per_device_batch_size</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 4</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --num_beams</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 4</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --test_batch_size</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --num_workers</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span></span></code></pre></div><p>You should see <code>Added N semantic-id tokens</code> → <code>Model saved to ...</code> → <code>Test results: {...}</code>.</p><blockquote><p>Offline / no access to the HuggingFace Hub: the legacy alias <code>t5-small</code> may not resolve, so use the canonical repo id: <code>--base_model google-t5/t5-small</code>.</p></blockquote><hr><h2 id="_5-real-data-pipeline-movielens-1m" tabindex="-1">5. Real-Data Pipeline (MovieLens-1M) <a class="header-anchor" href="#_5-real-data-pipeline-movielens-1m" aria-label="Permalink to “5. Real-Data Pipeline (MovieLens-1M)”">​</a></h2><p>Real data needs semantic IDs aligned with <code>inter.json</code>, so it is a two-stage RQ-VAE → TIGER pipeline:</p><ol><li><p><strong>Build interaction sequences</strong>:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run_tiger_movielens.py</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --mode</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> prepare-data</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --ratings_path</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./data/ml-1m/ratings.dat</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --data_inter_path</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./data/ml-1m/tiger/inter.json</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --min_seq_len</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --max_his_len</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 20</span></span></code></pre></div><p>This orders interactions by timestamp, filters users with too few interactions, remaps movie ids to contiguous 1-based item ids, and also writes <code>movie_id_map.json</code>.</p></li><li><p><strong>Generate semantic IDs</strong>: prepare item embeddings for the same item ids (e.g. the text/ID embeddings produced by HLLM preprocessing), then train an <code>run_rqvae_amazon_books.py</code>-style RQ-VAE and export <code>semantic_ids.json</code>. <strong>The RQ-VAE output must be keyed by the same item ids as step 1</strong>, otherwise <code>inter.json</code> and <code>semantic_ids.json</code> will not line up.</p></li><li><p><strong>Train and test</strong>:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run_tiger_movielens.py</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --mode</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> train</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --data_inter_path</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./data/ml-1m/tiger/inter.json</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --data_indice_path</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./data/ml-1m/tiger/semantic_ids.json</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --output_dir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./ckpt/tiger_ml</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run_tiger_movielens.py</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --mode</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --ckpt_path</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./ckpt/tiger_ml</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --data_inter_path</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./data/ml-1m/tiger/inter.json</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --data_indice_path</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./data/ml-1m/tiger/semantic_ids.json</span></span></code></pre></div></li></ol><p>The Amazon-Books real-data flow is identical: produce <code>semantic_ids.json</code> with <code>run_rqvae_amazon_books.py</code>, prepare <code>inter.json</code>, then <code>--mode train</code> / <code>--mode test</code>.</p><hr><h2 id="_6-evaluation" tabindex="-1">6. Evaluation <a class="header-anchor" href="#_6-evaluation" aria-label="Permalink to “6. Evaluation”">​</a></h2><p>The <code>test</code> stage runs constrained beam search per test sample:</p><ul><li>A <code>Trie</code> builds the <code>prefix_allowed_tokens_fn</code> so each step only allows the next token of a legal semantic ID.</li><li><code>--num_beams</code> is also used as <code>num_return_sequences</code> to obtain top-N candidates; <code>--filter_items</code> pushes any generated result outside the legal item set to a very low score.</li><li>Metrics are leave-one-out <code>hit@k</code> and <code>ndcg@k</code> (each user has a single ground truth, so IDCG=1). Configure with <code>--metrics hit@1,hit@5,hit@10,ndcg@5,ndcg@10</code>.</li></ul><hr><h2 id="_7-troubleshooting" tabindex="-1">7. Troubleshooting <a class="header-anchor" href="#_7-troubleshooting" aria-label="Permalink to “7. Troubleshooting”">​</a></h2><ul><li><strong><code>OSError: We couldn&#39;t connect to &#39;https://huggingface.co&#39;</code></strong>: offline, use <code>--base_model google-t5/t5-small</code> (canonical repo id) and make sure the weights are cached locally.</li><li><strong><code>Trainer.__init__() got an unexpected keyword argument &#39;tokenizer&#39;</code></strong>: <code>transformers&gt;=5</code> renamed the <code>tokenizer</code> argument to <code>processing_class</code>; the script auto-adapts via the signature, no manual change needed.</li><li><strong><code>&#39;TIGERModel&#39; object has no attribute &#39;model_parallel&#39;</code></strong>: the legacy T5 model-parallel guards are no longer initialized in <code>transformers&gt;=5</code>; <code>TIGERModel.__init__</code> now sets <code>model_parallel=False</code> / <code>device_map=None</code>, so multi-GPU DataParallel works too.</li><li><strong>Outputs are always sub-words / accuracy is abnormally low</strong>: confirm that training actually ran <code>add_tokens</code> + <code>resize_token_embeddings</code> (the log shows <code>Added N semantic-id tokens</code>) and that <code>test</code> loads the vocabulary from the <code>--output_dir</code> saved during training.</li></ul>`,38)])])}const g=i(n,[["render",o]]);export{k as __pageData,g as default};
